INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES
('foundation', 'common-vocabulary', 'beginner', 'What do you use to brush your teeth?', '["Toothbrush", "Comb", "Spoon", "Fork"]', 0, 'A toothbrush is used to clean teeth. Pattern: Daily object + its primary function.', 'easy'),
