('foundation', 'common-vocabulary', 'beginner', 'What do you do when something is funny?', '["Laugh", "Cry", "Sleep", "Work"]', 0, 'Laugh is the action of expressing amusement. Emotion-related verb.', 'easy'),
('foundation', 'common-vocabulary', 'beginner', 'What do you do with water?', '["Drink", "Read", "Write", "Draw"]', 0, 'Drink means to swallow liquid. Essential daily action.', 'easy'),
